export type ClientPath = keyof Client;
export type HttpMethod = 'ALL' | 'DELETE' | 'GET' | 'PATCH' | 'POST' | 'PUT';
export type ClientMethod<P extends ClientPath> = Extract<keyof Client[P], HttpMethod>;
export type ClientRoute<P extends ClientPath, M extends ClientMethod<P>> = Client[P][M];
export type ClientRequest<P extends ClientPath, M extends ClientMethod<P>> =
  ClientRoute<P, M> extends {
    request: infer Request;
  }
    ? Request
    : never;
export type ClientResponse<P extends ClientPath, M extends ClientMethod<P>> =
  ClientRoute<P, M> extends {
    response: infer Response;
  }
    ? Response
    : never;
export type ClientResponseKind<P extends ClientPath, M extends ClientMethod<P>> =
  ClientRoute<P, M> extends {
    responseType: infer ResponseType;
  }
    ? ResponseType
    : never;
